#[test]
fn render_summary_matches_page_summary() {
    let from_file: PolicyPackBetaRenderSummary = load("render_summary.json");
    let page: PolicyPackBetaPage = load("page.json");
    let from_page = PolicyPackBetaRenderSummary::from_page(&page);
    assert_eq!(from_file, from_page);
}
